import React, { useEffect, useState } from 'react';
import { fetchPlans } from './api';

function App() {
  const [plans, setPlans] = useState([]);

  useEffect(() => {
    // Sayfa yüklendiğinde planları getir
    const getPlans = async () => {
      try {
        const { data } = await fetchPlans();
        setPlans(data);
        console.log("Backend'den gelen veriler:", data);
      } catch (error) {
        console.error("Bağlantı hatası:", error);
      }
    };
    getPlans();
  }, []);

  return (
    <div className="min-h-screen bg-[#fdf4e3] p-10"> {/* Butter Yellow arka plan */}
      <h1 className="text-3xl font-bold text-[#f8ad9d] mb-5">Planly Bağlantı Testi</h1>

      {plans.length === 0 ? (
        <p>Henüz plan yok veya yükleniyor...</p>
      ) : (
        <ul className="space-y-4">
          {plans.map((plan) => (
            <li key={plan._id} className="bg-white p-4 rounded-lg shadow-sm border-l-4 border-[#f8ad9d]">
              <strong className="text-lg">{plan.examType}</strong>
              <p className="text-gray-600">Konular: {plan.topics.join(', ')}</p>
              <p className="text-sm text-gray-400">{plan.studyTime} Saat</p>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default App;
